// generar_262_trucos_entrenamiento.js
// CHIQUI Entre Señales — Trucos practicados en Entrenamiento
//
// IMPORTANTE: primero corre sql_262_trucos_entrenamiento.sql en
// Supabase (New snippet) — agrega la columna detalle a enriquecimientos.
//
// La actividad "🎓 Entrenamiento" del grupo Enriquecimiento ahora
// incluye, además de la duración, chips multi-selección con los trucos
// u órdenes practicados en la sesión:
//
//   Sentarse · Dar la pata · Acostarse · Hacerse el muerto ·
//   Dar un beso · Quedarse quieto · No morder · Traer objetos ·
//   No tirar la correa
//
// Se marcan los que se practicaron ese día y se guardan por sesión en
// la columna detalle (texto separado por comas). Al editar el día, los
// trucos marcados se reconstruyen. Registrar por sesión (y no como
// "aprendido" único) permite al análisis futuro:
//   - Detectar cuándo apareció cada truco por primera vez (= cuándo
//     empezó a aprenderlo).
//   - Mostrar el truco más practicado.
//   - Ver la progresión del repertorio en el tiempo.
//
// Para agregar trucos al catálogo: una línea en TRUCOS_ENTRENAMIENTO.
//
// NOTA: este script escribe app/registro-diario/page.tsx completo e
// incluye los cambios del 260 y 261 (enriquecimiento, cuidados e
// hitos). Corre sus SQL antes si aún no lo has hecho.
//
// Uso:
//   1) SQL primero: sql_262_trucos_entrenamiento.sql → Run
//   2) node generar_262_trucos_entrenamiento.js
//   3) git add . && commit && push

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: 'app/registro-diario/page.tsx',
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 1 archivo escrito (incluye 260 + 261 + 262).')
  console.log('Recuerda: SQL primero, luego git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
